import type { Broker } from "./broker.js";
import type { Tick, Granularity, Position } from "./types.js";

/** Context passed to a strategy on each tick */
export interface StrategyContext {
  broker: Broker;
  /** True during candle replay (backfill recovery) — skip order placement */
  backfilling?: boolean;
}

/** Recovery mode configuration for live trading */
export type RecoveryConfig =
  | { mode: "clean" }
  | { mode: "backfill"; lookback: number; granularity: Granularity }
  | { mode: "checkpoint" }
  | { mode: "custom" };

/**
 * Whether the strategy requires, forbids, or allows hedging accounts.
 * - "required" — needs hedging (simultaneous long/short on same instrument)
 * - "forbidden" — assumes netting (one position per instrument)
 * - "allowed" — works either way
 */
export type HedgingMode = "required" | "forbidden" | "allowed";

/** A single indicator row for display on the live page */
export interface StrategyIndicator {
  label: string;
  instrument?: string;
  value: string;
  signal?: "buy" | "sell" | "neutral" | "warn";
}

/** A strategy position for display */
export interface StrategyPosition {
  instrument: string;
  side: "buy" | "sell";
  entryPrice: number;
  pnl?: number;
  detail?: string;
}

/** Generic state snapshot returned by getState() for live display */
export interface StrategyStateSnapshot {
  phase: string;
  detail?: string;
  indicators: StrategyIndicator[];
  positions: StrategyPosition[];
}

/** Abstract strategy interface */
export interface Strategy {
  readonly name: string;
  readonly hedging: HedgingMode;

  /** Instruments this strategy needs streamed. If absent, the runner uses a default set. */
  readonly instruments?: readonly string[];

  /** Called once when the strategy starts */
  init(ctx: StrategyContext): Promise<void>;

  /** Called on each price tick */
  onTick(ctx: StrategyContext, tick: Tick): Promise<void>;

  /** Called when the strategy is stopped */
  dispose(): Promise<void>;

  /** Return current strategy state for live monitoring */
  getState(): StrategyStateSnapshot;

  /** For "checkpoint" recovery: return serializable state */
  checkpoint?(): unknown;

  /** For "checkpoint" recovery: restore from serialized state */
  restore?(state: unknown): void;

  /** For "custom" recovery: strategy handles its own recovery */
  recover?(ctx: StrategyContext, positions: Position[]): Promise<void>;
}

#core/types.js:
/** A currency pair like "EUR_USD" (OANDA format uses underscore) */
export type Instrument = string;

/** OHLCV candle */
export interface Candle {
  timestamp: number;
  open: number;
  high: number;
  low: number;
  close: number;
  volume: number;
}

/** A price tick with bid/ask */
export interface Tick {
  instrument: Instrument;
  timestamp: number;
  bid: number;
  ask: number;
}

/** Order side */
export type Side = "buy" | "sell";

/** Order types */
export type OrderType = "market" | "limit" | "stop";

/** Order request sent to a broker */
export interface OrderRequest {
  instrument: Instrument;
  side: Side;
  type: OrderType;
  units: number;
  price?: number; // required for limit/stop
}

/** Order response from broker */
export interface OrderResult {
  id: string;
  instrument: Instrument;
  side: Side;
  units: number;
  filledPrice: number;
  timestamp: number;
}

/** Current open position */
export interface Position {
  instrument: Instrument;
  side: Side;
  units: number;
  averagePrice: number;
  unrealizedPL: number;
}

/** Account state */
export interface AccountSummary {
  balance: number;
  unrealizedPL: number;
  currency: string;
  openPositions: number;
  hedgingEnabled: boolean;
}

/** Candle granularity */
export type Granularity =
  | "S5"
  | "S10"
  | "S15"
  | "S30"
  | "M1"
  | "M2"
  | "M4"
  | "M5"
  | "M10"
  | "M15"
  | "M30"
  | "H1"
  | "H2"
  | "H3"
  | "H4"
  | "H6"
  | "H8"
  | "H12"
  | "D"
  | "W"
  | "M";

/** Seconds per candle for each granularity, ordered smallest to largest */
export const GRANULARITY_SECONDS: Record<Granularity, number> = {
  S5: 5, S10: 10, S15: 15, S30: 30,
  M1: 60, M2: 120, M4: 240, M5: 300,
  M10: 600, M15: 900, M30: 1800,
  H1: 3600, H2: 7200, H3: 10800, H4: 14400,
  H6: 21600, H8: 28800, H12: 43200,
  D: 86400, W: 604800, M: 2592000,
};

/** All granularities sorted chronologically (smallest to largest) */
export const GRANULARITIES_SORTED: Granularity[] = (
  Object.keys(GRANULARITY_SECONDS) as Granularity[]
).sort((a, b) => GRANULARITY_SECONDS[a] - GRANULARITY_SECONDS[b]);

#core/broker.js:
import type {
  AccountSummary,
  Candle,
  Granularity,
  Instrument,
  OrderRequest,
  OrderResult,
  Position,
  Tick,
} from "./types.js";

/** Abstract broker interface — implemented by OANDA, Tradovate, etc. */
export interface Broker {
  readonly name: string;

  // Account
  getAccountSummary(): Promise<AccountSummary>;
  getPositions(): Promise<Position[]>;

  // Orders
  submitOrder(order: OrderRequest): Promise<OrderResult>;
  closePosition(instrument: Instrument): Promise<OrderResult>;

  // Market data
  getCandles(
    instrument: Instrument,
    granularity: Granularity,
    count: number,
  ): Promise<Candle[]>;

  getCandlesByRange(
    instrument: Instrument,
    granularity: Granularity,
    from: Date,
    to: Date,
  ): Promise<Candle[]>;

  getPrice(instrument: Instrument): Promise<Tick>;

  // Streaming
  streamPrices(
    instruments: Instrument[],
    onTick: (tick: Tick) => void,
  ): Promise<{ close: () => void }>;
}

