/** Major USD pairs — USD is base or quote */
export const USD_MAJORS = [
  "EUR_USD",
  "GBP_USD",
  "USD_JPY",
  "USD_CAD",
  "USD_CHF",
  "AUD_USD",
  "NZD_USD",
] as const;

/** Cross pairs derivable from USD majors */
export const CROSSES = [
  "EUR_GBP",
  "EUR_JPY",
  "EUR_CAD",
  "EUR_CHF",
  "EUR_AUD",
  "EUR_NZD",
  "GBP_JPY",
  "GBP_CAD",
  "GBP_CHF",
  "GBP_AUD",
  "GBP_NZD",
  "AUD_JPY",
  "AUD_CAD",
  "AUD_CHF",
  "AUD_NZD",
  "NZD_JPY",
  "NZD_CAD",
  "NZD_CHF",
  "CAD_JPY",
  "CAD_CHF",
  "CHF_JPY",
] as const;

/** All instruments we track */
export const ALL_INSTRUMENTS = [...USD_MAJORS, ...CROSSES] as const;

/** Currency codes involved */
export const CURRENCIES = ["EUR", "GBP", "USD", "JPY", "CAD", "CHF", "AUD", "NZD"] as const;

export type Currency = (typeof CURRENCIES)[number];

/**
 * Parse an instrument into its base and quote currencies.
 * "EUR_USD" → ["EUR", "USD"]
 */
export function parsePair(instrument: string): [Currency, Currency] {
  const [base, quote] = instrument.split("_");
  return [base as Currency, quote as Currency];
}

/**
 * Given two currencies, find the instrument name (OANDA format).
 * Returns the pair in the correct OANDA order, or null if not found.
 */
export function findInstrument(a: Currency, b: Currency): string | null {
  const direct = `${a}_${b}`;
  const reverse = `${b}_${a}`;
  const all = ALL_INSTRUMENTS as readonly string[];
  if (all.includes(direct)) return direct;
  if (all.includes(reverse)) return reverse;
  return null;
}

/**
 * For a given cross pair, find the two USD-leg majors that imply it.
 * e.g., "AUD_CAD" → { legA: "AUD_USD", legB: "USD_CAD" }
 *
 * The implied rate is computed as:
 *   implied = getUsdRate(base) / getUsdRate(quote)
 * where getUsdRate converts each currency to "units of currency per 1 USD"
 */
export function findTriangle(cross: string): { legA: string; legB: string } | null {
  const [base, quote] = parsePair(cross);
  if (base === "USD" || quote === "USD") return null; // not a cross

  const legA = findInstrument(base, "USD" as Currency);
  const legB = findInstrument(quote, "USD" as Currency);

  if (!legA || !legB) return null;
  return { legA, legB };
}

#backtest/types.js:
import type { Granularity, Instrument } from "../core/types.js";

/** Configuration for a backtest run */
export interface BacktestConfig {
  /** Which granularity data to replay */
  granularity: Granularity;
  /** Starting balance in account currency */
  initialBalance: number;
  /** Simulated spread — either a flat number or per-instrument map (absolute price units) */
  spread: number | Record<string, number>;
  /** Instruments to load (defaults to all if not set) */
  instruments?: Instrument[];
  /** Start date filter "YYYY-MM-DD" inclusive (optional) */
  fromDate?: string;
  /** End date filter "YYYY-MM-DD" inclusive (optional) */
  toDate?: string;
  /** Multiply all spreads by this factor (default: 1.0). Use 2.0 to stress-test wider spreads */
  spreadMultiplier?: number;
  /** Delay order execution by this many ticks on the same instrument (default: 0) */
  executionDelay?: number;
  /** Use time-varying spread model (wider at session open, tighter during overlap) */
  timeVaryingSpread?: boolean;
  /** Random slippage in pips added to each fill (default: 0). Simulates execution quality. */
  slippagePips?: number;
}

/** Signal snapshot captured at entry or exit */
export interface SignalSnapshot {
  zScore: number;
  deviation: number;
  deviationMean: number;
  deviationStd: number;
  impliedRate: number;
  actualRate: number;
  legA: string;
  legAPrice: number;
  legB: string;
  legBPrice: number;
}

/** A single completed trade (open → close) */
export interface Trade {
  instrument: Instrument;
  side: "buy" | "sell";
  units: number;
  entryPrice: number;
  exitPrice: number;
  entryTime: number;
  exitTime: number;
  pnl: number;
  entrySignal?: SignalSnapshot;
  exitSignal?: SignalSnapshot;
}

/** Summary statistics from a backtest */
export interface BacktestResult {
  config: BacktestConfig;
  startTime: number;
  endTime: number;
  totalTicks: number;
  initialBalance: number;
  finalBalance: number;
  totalPnL: number;
  returnPct: number;
  maxDrawdown: number;
  maxDrawdownPct: number;
  sharpeRatio: number;
  totalTrades: number;
  winRate: number;
  avgWin: number;
  avgLoss: number;
  profitFactor: number;
  trades: Trade[];
  /** Equity curve: array of [timestamp, equity] */
  equityCurve: [number, number][];
}
